package genxsolution.vms.vmsbackend.maintenance_management.maintenance_assignment.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_assignment.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_assignment.mapper.MaintenanceAssignmentMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_assignment.repository.MaintenanceAssignmentRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenanceAssignmentService { private final MaintenanceAssignmentRepository repository; private final MaintenanceAssignmentMapper mapper; public MaintenanceAssignmentService(MaintenanceAssignmentRepository repository,MaintenanceAssignmentMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenanceAssignmentResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenanceAssignmentResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceAssignment", String.valueOf(id))); } public MaintenanceAssignmentResponse create(MaintenanceAssignmentUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenanceAssignmentResponse update(UUID id,MaintenanceAssignmentUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceAssignment", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenanceAssignment", String.valueOf(id)); } }
